#include "../common.h"
#include "./kernel_fin.c"
#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#ifdef TIMING
#include "timing.h"
extern float kernel_time, d2h_time, h2d_time;
#endif

void 
master(	fp timeinst,
		fp *initvalu,
		fp *parameter,
		fp *finavalu,
		fp *com,

		long long *timecopyin,
		long long *timekernel,
		long long *timecopyout)
{


	long long time0;
	long long time1;
	long long time2;
	long long time3;


	int i;


	int initvalu_offset_ecc;																
	int initvalu_offset_Dyad;															
	int initvalu_offset_SL;																
	int initvalu_offset_Cyt;																

	time0 = get_time();


	fp JCaDyad;
	fp JCaSL;
	fp JCaCyt;


	initvalu_offset_ecc = 0;												
	initvalu_offset_Dyad = 46;												
	initvalu_offset_SL = 61;												
	initvalu_offset_Cyt = 76;												


	ecc(	timeinst,
			initvalu,
			initvalu_offset_ecc,
			parameter,
			0,
			finavalu);


	JCaDyad = cam(	timeinst,
					initvalu,
					initvalu_offset_Dyad,
					parameter,
					2,
					finavalu,
					initvalu[35]*1e3);


	JCaSL = cam(	timeinst,
					initvalu,
					initvalu_offset_SL,
					parameter,
					5,
					finavalu,
					initvalu[36]*1e3);


	JCaCyt = cam(	timeinst,
					initvalu,
					initvalu_offset_Cyt,
					parameter,
					10,
					finavalu,
					initvalu[37]*1e3);


	com[0] = JCaDyad;
	com[1] = JCaSL;
	com[2] = JCaCyt;

	time1 = get_time();


	time2 = get_time();


	time3 = get_time();


	timecopyin[0] = timecopyin[0] + (time1-time0);
	timekernel[0] = timekernel[0] + (time2-time1);
	timecopyout[0] = timecopyout[0] + (time3-time2);


	kernel_fin(	initvalu,
				initvalu_offset_ecc,
				initvalu_offset_Dyad,
				initvalu_offset_SL,
				initvalu_offset_Cyt,
				parameter,
				finavalu,
				com[0],
				com[1],
				com[2]);


	for(i=0; i<EQUATIONS; i++){
		if (isnan(finavalu[i]) == 1){ 
			finavalu[i] = 0.0001;												
		}
		else if (isinf(finavalu[i]) == 1){ 
			finavalu[i] = 0.0001;												
		}
	}

#ifdef TIMING
    h2d_time += (time1-time0)/1000.0;
    kernel_time += (time2-time1)/1000.0;
    d2h_time += (time3-time2)/1000.0;
#endif


}
